export const getGetSupplierPriceComparisonUrl = (params: GetSupplierPriceComparisonParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/price-monitor/supplier-comparison?${stringifiedParams}` : `/api/price-monitor/supplier-comparison`
}

